// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.concurrent.atomic.AtomicBoolean;

import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinFactorCostModel;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost.BagEstimate;
import org.eclipse.rdf4j.sail.lmdb.estimation.QuadSnapshotIdentity;
import org.eclipse.rdf4j.sail.lmdb.estimation.RowEvidence;
import org.junit.jupiter.api.Test;

class EstimateEvidenceResolverTest {

	private static final QuadSnapshotIdentity IDENTITY = new QuadSnapshotIdentity(7L, 11L, 3L);

	@Test
	void exactStorageAndFiniteEvidenceHaveStablePrecedence() {
		EstimateContext context = context(JoinFactorCostModel.EstimationTier.STANDARD, false);
		EstimateCandidate synopsis = candidate(9.0d, 8.0d, 12.0d, true, EstimateCandidate.Kind.SYNOPSIS, 20L,
				IDENTITY);
		EstimateCandidate finite = candidate(5.0d, 5.0d, 5.0d, true, EstimateCandidate.Kind.FINITE_RELATION, 10L,
				IDENTITY);
		EstimateCandidate exact = candidate(4.0d, 4.0d, 4.0d, true, EstimateCandidate.Kind.EXACT_STORAGE, 1L,
				IDENTITY);

		BagEstimate resolved = new EstimateEvidenceResolver().resolve(List.of(synopsis, finite, exact), context);

		assertEquals(4.0d, resolved.rows());
		assertEquals("exact_storage", resolved.source());
	}

	@Test
	void staleEvidenceIsRejectedBeforeRanking() {
		QuadSnapshotIdentity staleIdentity = new QuadSnapshotIdentity(IDENTITY.storeIdHigh(), IDENTITY.storeIdLow(), 2L);
		EstimateCandidate staleExact = candidate(0.0d, 0.0d, 0.0d, true, EstimateCandidate.Kind.EXACT_STORAGE, 100L,
				staleIdentity);
		EstimateCandidate current = candidate(8.0d, 6.0d, 10.0d, true, EstimateCandidate.Kind.SYNOPSIS, 1L,
				IDENTITY);

		BagEstimate resolved = new EstimateEvidenceResolver().resolve(List.of(staleExact, current),
				context(JoinFactorCostModel.EstimationTier.STANDARD, false));

		assertEquals(8.0d, resolved.rows());
	}

	@Test
	void incompleteSampleCanNeverResolveToExactZero() {
		EstimateCandidate sampledZero = candidate(0.0d, 0.0d, 0.0d, false, EstimateCandidate.Kind.SYNOPSIS, 1L,
				IDENTITY);

		BagEstimate resolved = new EstimateEvidenceResolver().resolve(List.of(sampledZero),
				context(JoinFactorCostModel.EstimationTier.STANDARD, false));

		assertTrue(resolved.rows() > 0.0d);
		assertEquals(0.0d, resolved.metrics().get("optimizer.estimateLowerRows"));
		assertTrue(resolved.metrics().get("optimizer.estimateUpperRows") > 0.0d);
	}

	@Test
	void exactDecisionProbeRunsOnlyWhenTierAndWinnerOverlapAllowIt() {
		EstimateEvidenceResolver resolver = new EstimateEvidenceResolver();
		EstimateCandidate synopsis = candidate(10.0d, 5.0d, 20.0d, true, EstimateCandidate.Kind.SYNOPSIS, 1L,
				IDENTITY);
		AtomicBoolean invoked = new AtomicBoolean();

		resolver.resolveForDecision(List.of(synopsis), context(JoinFactorCostModel.EstimationTier.STANDARD, true),
				() -> {
					invoked.set(true);
					return candidate(7.0d, 7.0d, 7.0d, true, EstimateCandidate.Kind.EXACT_STORAGE, 2L, IDENTITY);
				});
		assertFalse(invoked.get());

		BagEstimate exact = resolver.resolveForDecision(List.of(synopsis),
				context(JoinFactorCostModel.EstimationTier.DECISION_EXACT, true), () -> {
					invoked.set(true);
					return candidate(7.0d, 7.0d, 7.0d, true, EstimateCandidate.Kind.EXACT_STORAGE, 2L, IDENTITY);
				});
		assertTrue(invoked.get());
		assertEquals(7.0d, exact.rows());
	}

	private static EstimateCandidate candidate(double rows, double lower, double upper, boolean complete,
			EstimateCandidate.Kind kind, long freshness, QuadSnapshotIdentity identity) {
		return new EstimateCandidate(BagEstimate.heuristic(rows, kind.name().toLowerCase()),
				new RowEvidence(rows, lower, upper, 0.8d, complete, identity, 9L, kind.name().toLowerCase()),
				kind, freshness);
	}

	private static EstimateContext context(JoinFactorCostModel.EstimationTier tier, boolean exactProbePermitted) {
		return EstimateContext.root(new SingletonSet(), IDENTITY, 9L)
				.withEstimationTier(tier)
				.withExactProbePermission(exactProbePermitted);
	}
}
